#include <stdio.h>
#include <stdlib.h>
#include <omp.h>
#include <math.h>

#define fp double

#define NUMBER_PAR_PER_BOX 100
#define NUMBER_THREADS 128

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct {
    fp x, y, z;
} THREE_VECTOR;

typedef struct {
    fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str {
    int x, y, z;
    int number;
    long offset;
} nei_str;

typedef struct box_str {
    int x, y, z;
    int number;
    long offset;
    int nn;
    nei_str nei[26];
} box_str;

typedef struct par_str {
    fp alpha;
} par_str;

typedef struct dim_str {
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;
    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

void kernel_cpu(par_str par, dim_str dim, box_str* box, FOUR_VECTOR* rv, fp* qv, FOUR_VECTOR* fv) {
    int bx, tx, wtx, k, j;
    fp a2, r2, u2, vij, fs, fxij, fyij, fzij;
    THREE_VECTOR d;
    FOUR_VECTOR rA, rB;
    fp qB;

    #pragma omp parallel for num_threads(dim.cores_arg) private(bx, tx, wtx, k, j, a2, r2, u2, vij, fs, fxij, fyij, fzij, d, rA, rB, qB)
    for (bx = 0; bx < dim.number_boxes; bx++) {
        tx = omp_get_thread_num();
        wtx = tx;

        // home box
        int first_i = box[bx].offset;
        FOUR_VECTOR* rA = &rv[first_i];
        FOUR_VECTOR* fA = &fv[first_i];

        // nei box loop
        for (k = 0; k <= box[bx].nn; k++) {
            if (k == 0) {
                // set first box to be processed to home box
                int pointer = bx;
            } else {
                // remaining boxes are nei boxes
                int pointer = box[bx].nei[k - 1].number;
            }

            // nei box - box parameters
            int first_j = box[pointer].offset;

            // nei box - distance, (force), charge and (type) parameters
            FOUR_VECTOR* rB = &rv[first_j];
            fp* qB = &qv[first_j];

            // calculation
            for (wtx = tx; wtx < NUMBER_PAR_PER_BOX; wtx += dim.cores_arg) {
                r2 = (fp)rA[wtx].v + (fp)rB[0].v - DOT((fp)rA[wtx], (fp)rB[0]);
                u2 = 2 * par.alpha * par.alpha * r2;
                vij = exp(-u2);
                fs = 2 * vij;

                d.x = (fp)rA[wtx].x - (fp)rB[0].x;
                fxij = fs * d.x;
                d.y = (fp)rA[wtx].y - (fp)rB[0].y;
                fyij = fs * d.y;
                d.z = (fp)rA[wtx].z - (fp)rB[0].z;
                fzij = fs * d.z;

                fA[wtx].v += (double)((fp)qB[0] * vij);
                fA[wtx].x += (double)((fp)qB[0] * fxij);
                fA[wtx].y += (double)((fp)qB[0] * fyij);
                fA[wtx].z += (double)((fp)qB[0] * fzij);
            }
        }
    }
}
